#### 3. Services (`src/services/geminiService.ts`)
*Note: Please update the API Key access to `import.meta.env.VITE_GOOGLE_API_KEY`.*

```typescript
import { GoogleGenAI, Type, Schema } from "@google/genai";
import { ScriptAnalysis, ModelType } from "../types";

// UPDATE THIS LINE FOR LOVABLE/VITE ENVIRONMENT
const apiKey = import.meta.env.VITE_GOOGLE_API_KEY;
if (!apiKey) console.warn("Missing VITE_GOOGLE_API_KEY");
const ai = new GoogleGenAI({ apiKey: apiKey || "" });

const SYSTEM_INSTRUCTION = `
你是一位拥有多年经验的极其专业的视频创作者和分镜画师，对3到15分钟的故事性视频有着非常深刻的理解。
你应站在整个脚本立意的全局视角，拆解脚本，并将其设计成对应的分镜草图。
同时，您需要提供与分镜草图一一对应的人物台词、旁白等必要的画面匹配信息。

整体语调：自信、幽默且富有经验，像一位和蔼又专业的行业前辈。不啰嗦，不说废话。

规则:
1. 首先，对用户脚本进行全局立意的概述，用风趣、幽默且浅显的语言总结核心主题和故事结构。
2. 将脚本分解为所有必要的关键场景或镜头（**必须完整覆盖用户提供的脚本内容，不要遗漏任何情节，哪怕镜头数量较多**）。
3. 对于每个分镜，精确对应地写出人物台词、旁白或其他画面中必须匹配的文本信息。
4. 提供 "visual_prompt"：用于 AI 生成图片的英文提示词（专注于构图、主体、风格、光线）。为了更好的生图效果，请务必使用英文撰写此字段。
5. **明确区分景别 (Shot Size) 和 拍摄角度 (Camera Angle)。**
6. 提供 "director_note"：提供实用性建议，如 '在这个镜头中，建议使用特写来强调角色的情绪波动'。
7. 除 "visual_prompt" 外，所有内容必须使用**中文**回答。
`;

const RESPONSE_SCHEMA: Schema = {
  type: Type.OBJECT,
  properties: {
    title: { type: Type.STRING, description: "分镜脚本的标题" },
    overview: { type: Type.STRING, description: "对脚本核心主题和结构的幽默且有洞察力的总结（中文）。" },
    style_notes: { type: Type.STRING, description: "总体视觉风格和氛围建议（中文）。" },
    shots: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          id: { type: Type.INTEGER },
          scene_number: { type: Type.STRING, description: "例如：'第1场' 或 '场景 2'" },
          shot_description: { type: Type.STRING, description: "该镜头发生的简要描述（中文）。" },
          visual_prompt: { type: Type.STRING, description: "用于生成草图的详细视觉描述。请使用英文 (English) 以获得最佳图像生成效果。包含风格（如 'storyboard sketch', 'cinematic lighting'）。" },
          shot_size: { type: Type.STRING, description: "景别。例如：特写、中景、全景、大远景（中文）。" },
          camera_angle: { type: Type.STRING, description: "拍摄角度。例如：仰拍、俯拍、平视、上帝视角、荷兰角（中文）。" },
          camera_movement: { type: Type.STRING, description: "例如：固定镜头、向右摇摄、手持跟拍（中文）。" },
          lighting: { type: Type.STRING, description: "例如：高调光、剪影、清晨自然光（中文）。" },
          audio_dialogue: { type: Type.STRING, description: "与该镜头精确匹配的对话或旁白（中文）。" },
          director_note: { type: Type.STRING, description: "关于如何有效执行该镜头的专家建议（中文）。" }
        },
        required: ["id", "scene_number", "shot_description", "visual_prompt", "shot_size", "camera_angle", "camera_movement", "lighting", "audio_dialogue", "director_note"]
      }
    }
  },
  required: ["title", "overview", "style_notes", "shots"]
};

export const analyzeScript = async (script: string, requirements: string): Promise<ScriptAnalysis> => {
  try {
    const userPrompt = `
      这是我需要可视化的脚本内容：
      ---
      ${script}
      ---

      额外的导演要求/限制：
      ${requirements || "无具体要求，请运用你的专业判断。"}

      请将其拆解为分镜列表。捕捉故事精髓，生成关键镜头。
      注意：请确保覆盖脚本的所有部分，如果脚本较长，请生成足够数量的分镜来完整表达故事，不要被默认数量限制。
    `;

    const response = await ai.models.generateContent({
      model: ModelType.TEXT_ANALYSIS,
      contents: userPrompt,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: RESPONSE_SCHEMA,
        temperature: 0.7,
      }
    });

    let text = response.text;
    if (!text) throw new Error("No response from AI");

    if (text.startsWith("```json")) {
      text = text.replace(/^```json\s*/, "").replace(/\s*```$/, "");
    } else if (text.startsWith("```")) {
      text = text.replace(/^```\s*/, "").replace(/\s*```$/, "");
    }

    return JSON.parse(text) as ScriptAnalysis;
  } catch (error) {
    console.error("Analysis Error:", error);
    throw error;
  }
};

export const generateShotImage = async (visualPrompt: string): Promise<string | null> => {
  try {
    const stylePrefix = "Professional movie storyboard sketch, masterpiece, rough charcoal and graphite style, deep shadows, high contrast noir aesthetic, atmospheric lighting, 16:9 widescreen composition. ";

    const finalPrompt = visualPrompt.includes("Professional movie storyboard sketch") 
      ? visualPrompt 
      : `${stylePrefix} Scene details: ${visualPrompt}`;

    const response = await ai.models.generateContent({
      model: ModelType.IMAGE_GENERATION,
      contents: {
        parts: [{ text: finalPrompt }]
      },
      config: {
        imageConfig: {
          aspectRatio: "16:9"
        }
      }
    });

    if (response.candidates && response.candidates[0].content.parts) {
       for (const part of response.candidates[0].content.parts) {
         if (part.inlineData) {
            return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
         }
       }
    }
    return null;
  } catch (error) {
    console.error("Image Generation Error:", error);
    return null; 
  }
};
```

#### 4. Services (`src/services/storageService.ts`)

```typescript
import { ScriptAnalysis, AppState, SavedProject } from '../types';

const STORAGE_KEY = 'storyboard_pro_projects';
const CURRENT_PROJECT_KEY = 'storyboard_pro_current';

export const saveProject = (state: AppState): void => {
  if (!state.analysis) return;
  const projects = getProjects();
  const projectId = state.analysis.title || 'untitled-project';
  const projectToSave: SavedProject = {
    id: projectId,
    title: state.analysis.title || '未命名项目',
    timestamp: Date.now(),
    overview: state.analysis.overview || '',
    state: state
  };

  const existingIndex = projects.findIndex(p => p.id === projectId);
  if (existingIndex >= 0) {
    projects[existingIndex] = projectToSave;
  } else {
    projects.unshift(projectToSave);
  }
  if (projects.length > 20) projects.pop();

  try {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(projects));
    localStorage.setItem(CURRENT_PROJECT_KEY, JSON.stringify(state));
  } catch (e) {
    console.error("Storage quota exceeded", e);
  }
};

export const getProjects = (): SavedProject[] => {
  try {
    const json = localStorage.getItem(STORAGE_KEY);
    return json ? JSON.parse(json) : [];
  } catch (e) {
    return [];
  }
};

export const loadLastSession = (): AppState | null => {
  try {
    const json = localStorage.getItem(CURRENT_PROJECT_KEY);
    return json ? JSON.parse(json) : null;
  } catch (e) {
    return null;
  }
};

export const deleteProject = (id: string): SavedProject[] => {
  const projects = getProjects().filter(p => p.id !== id);
  localStorage.setItem(STORAGE_KEY, JSON.stringify(projects));
  return projects;
};
```

#### 5. UI Components
Please create the following components in `src/components/`:

*   **Header.tsx**: (Use `Clapperboard` from lucide-react, layout width: `w-[92%] max-w-[1600px]`).
*   **SidebarNav.tsx**: (Vertical list, smooth scrolling, highlights active shot).
*   **ScriptDrawer.tsx**: (Right side sliding panel to view original script).
*   **ShotCard.tsx**: (The complex card with image, inputs, dropdowns for 'Shot Size' & 'Angle', version history, and print styles. Remember to use `aspect-video` for the image container).

#### 6. Main Application (`src/App.tsx`)
*   Implement the `App` component that integrates all the services and components above.
*   Include the logic for:
    *   File Upload (.txt/.md)
    *   Style Presets (including the custom 'Scott Style' prompt)
    *   Auto-save logic
    *   State management for `idle` -> `analyzing` -> `visualizing` -> `complete` steps.
    *   Manual scrolling vs IntersectionObserver logic.
    *   Ensure the main container uses `w-[92%] max-w-[1600px]`.

